// Validate + normalize the create request.
// Contract (INSTALL.md Step 7): { brandName, clientEmail, idempotencyKey? }
// idempotencyKey closes the create-then-crash-then-rerun duplicate window: a
// repeat POST with the same key returns the already-created sheet instead of
// making a second one.
const body = $input.first().json.body || {};
const brandName = body.brandName;
const clientEmail = body.clientEmail;
const idempotencyKey = body.idempotencyKey || '';
if (!brandName) throw new Error('missing brandName');
if (!clientEmail) throw new Error('missing clientEmail');
// Fleet template sheet the new client sheet is copied from.
const templateSheetId = '1RKgS5l-i6NBtf_vON49nBPdHe-F5W67RF9ym-S67L2c';
return [{ json: { brandName, clientEmail, idempotencyKey, templateSheetId } }];

// Grant the client edit access, then return the create contract.
// Response contract (QC.md 'Google Sheet Verification'): { sheetUrl, sheetId, sheetName }
const created = $input.first().json;
const sheetId = created.spreadsheetId;
const sheetName = created.properties ? created.properties.title : '';
const sheetUrl = created.spreadsheetUrl || ('https://docs.google.com/spreadsheets/d/' + sheetId + '/edit');
return [{ json: { success: true, sheetId, sheetName, sheetUrl } }];
